1	import crypto from 'crypto';
2	import {
3	  IGeneratedTest,
4	  IQuestion,
5	  IAIFeedback,
6	  IContentForAI,
7	  IUserAnswer,
8	  IMistake,
9	  TestGenerationProfile
10	} from '../types';
11	import {
12	  parseAndValidateEntQuestions,
13	  parseAndValidateRegularQuestions,
