34	/** Завершён ли узел live-сборкой из КТП (тогда нет сохранённого документа для кэша summary). */
35	async function isLiveBuiltFromKtp(subjectId: string): Promise<boolean> {
36	  const ktp = await KtpCatalog.findOne({ subjectId }).select('topics').lean();
