81	function lessonListItems(
82	  lessons: ICanonicalNodeLesson[],
83	  completedSet: Set<string>
84	): IRoadmapLessonListItem[] {
85	  let prevCompleted = true;
86	  return lessons.map((l, i) => {
87	    const completed = completedSet.has(l.lessonId);
88	    const locked = i > 0 && !prevCompleted;
89	    prevCompleted = completed;
90	    return { lessonId: l.lessonId, title: l.title, order: l.order, completed, locked };
91	  });
