170	  /**
171	   * Отметить урок прочитанным. Если lessonId не задан — завершаем первый незавершённый урок узла.
172	   * Последовательный гейтинг: нельзя завершить урок, пока не завершены предыдущие.
173	   */
174	  async markLessonRead(
175	    userId: string,
176	    subjectId: string,
177	    nodeId: string,
178	    lessonId?: string
179	  ): Promise<{ readCompletedAt: string; lessonId: string; allCompleted: boolean; nextLessonId: string | null }> {
180	    if (!mongoose.isValidObjectId(subjectId)) throw AppError.badRequest('Invalid subjectId');
181	
182	    const node = await this.resolveNode(subjectId, nodeId);
183	    const lessonIds = await nodeLessonIds(subjectId, node);
184	    if (lessonIds.length === 0) throw AppError.notFound('Lesson not found for this node');
185	
186	    let targetId = lessonId?.trim();
187	    if (!targetId) {
188	      const progress = await roadmapService.getNodeProgress(userId, subjectId, nodeId);
189	      const completed = new Set((progress?.lessons ?? []).map((l) => l.lessonId));
190	      targetId = lessonIds.find((id) => !completed.has(id)) ?? lessonIds[lessonIds.length - 1];
191	    }
192	
193	    // Валидация lessonId и последовательный гейтинг — в markLessonComplete.
194	    return roadmapService.markLessonComplete(userId, subjectId, nodeId, targetId);
195	  }
