445	  /** POST /tests/solo/answer (auth) */
446	  async submitSoloAnswer(req: Request, res: Response): Promise<void> {
447	    const userId = (req as any).user?.userId;
448	    const { soloSessionId, questionIndex, selectedOption }: {
449	      soloSessionId: string;
450	      questionIndex: number;
451	      selectedOption: string;
452	    } = req.body;
453	
454	    const session = await SoloSession.findById(soloSessionId);
455	    if (!session) throw AppError.notFound('Solo session not found');
456	    if (session.userId.toString() !== userId) throw AppError.forbidden('Access denied');
457	    if (session.isFinished) throw AppError.badRequest('Solo session already finished');
458	    if (session.currentQuestionIndex !== questionIndex) {
459	      throw AppError.badRequest('Question index mismatch');
460	    }
461	
462	    const test = await Test.findById(session.testId);
463	    if (!test) throw AppError.notFound('Test not found');
464	
465	    const question = test.questions[questionIndex];
466	    if (!question) throw AppError.badRequest('Invalid question index');
467	
468	    const elapsedMs = Math.max(0, Date.now() - session.questionStartedAt.getTime());
469	    const cappedMs = Math.min(elapsedMs, session.questionTimeLimitSec * 1000);
470	    const isCorrect = gradeAnswer(question as IQuestion, selectedOption || '');
471	    const questionScore = this.calculateSoloQuestionScore(isCorrect, cappedMs);
472	
473	    const nextIndex = questionIndex + 1;
474	    const isLastQuestion = nextIndex >= test.questions.length;
475	
476	    session.answers.push({
477	      questionIndex,
478	      selectedOption: selectedOption || '',
479	      isCorrect,
480	      responseTimeMs: cappedMs,
481	      questionScore
482	    });
483	    session.currentQuestionIndex = nextIndex;
484	    session.questionStartedAt = new Date();
485	    if (isLastQuestion) session.isFinished = true;
486	    await session.save();
487	
488	    success(res, {
489	      accepted: true,
490	      questionIndex,
491	      isCorrect,
492	      questionScore,
493	      responseTimeMs: cappedMs,
494	      finished: isLastQuestion,
495	      nextQuestionIndex: isLastQuestion ? null : nextIndex,
496	      questionStartedAt: isLastQuestion ? null : session.questionStartedAt
497	    }, 'Solo answer accepted');
498	  }
