1	import { Subject } from '../models';
2	import { IBook, IContentForAI, IGenerateTestDTO } from '../types';
3	import { AppError } from '../utils';
4	
5	/**
6	 * Загрузка текста книги/главы для ИИ (тесты, roadmap и т.д.).
7	 * Если передан topicFocus (из roadmap-узла), пытается найти подходящую главу
8	 * по названию и сужает контент; иначе отдаёт всю книгу с директивой topicFocus.
9	 */
10	export async function resolveBookContentForAI(dto: IGenerateTestDTO): Promise<{
11	  subject: NonNullable<Awaited<ReturnType<typeof Subject.findById>>>;
12	  book: IBook;
13	  contentForAI: IContentForAI;
14	}> {
15	  const subject = await Subject.findById(dto.subjectId);
16	  if (!subject) throw AppError.notFound('Subject not found');
17	
18	  const book = subject.books.find((b) => b._id?.toString() === dto.bookId);
19	  if (!book) throw AppError.notFound('Book not found');
20	
21	  let contentText = '';
22	  let chapterTitle = '';
23	  const topics: string[] = [];
24	  let resolvedChapterId = dto.chapterId;
25	
26	  if (!resolvedChapterId && dto.topicFocus && !dto.fullBook) {
27	    const focusLower = dto.topicFocus.toLowerCase();
28	    const matched = book.chapters.find(
29	      (ch) => ch.title.toLowerCase().includes(focusLower) || focusLower.includes(ch.title.toLowerCase())
30	    );
31	    if (matched) {
32	      resolvedChapterId = matched._id?.toString();
33	    }
34	  }
35	
36	  if (dto.fullBook || !resolvedChapterId) {
37	    contentText = subject.getBookContent(dto.bookId);
38	    chapterTitle = 'Вся книга';
39	    book.chapters.forEach((ch) => ch.topics.forEach((t) => topics.push(t.title)));
40	  } else {
41	    const chapter = book.chapters.find((c) => c._id?.toString() === resolvedChapterId);
42	    if (!chapter) throw AppError.notFound('Chapter not found');
43	    contentText = subject.getChapterContent(dto.bookId, resolvedChapterId!);
44	    chapterTitle = chapter.title;
45	    chapter.topics.forEach((t) => topics.push(t.title));
46	  }
47	
48	  if (!contentText?.trim()) {
49	    throw AppError.badRequest('No content available');
50	  }
51	
52	  const chapterTitles = [...book.chapters]
53	    .sort((a, b) => a.order - b.order)
54	    .map((c) => c.title);
55	
56	  const contentForAI: IContentForAI = {
57	    text: contentText,
58	    metadata: {
59	      subjectTitle: subject.title,
60	      bookTitle: book.title,
61	      chapterTitle: dto.fullBook ? undefined : chapterTitle,
