3	/** Краткое описание темы из её текста (или fallback на заголовок). */
4	export function makeChapterSummary(text: string, title: string, maxLen = 400): string {
5	  const raw = (text || '').trim();
6	  if (!raw) return title;
7	  if (raw.length <= maxLen) return raw;
