11	/** Текст одной темы книги (параграфы в порядке order). Используется билдером КТП-узлов. */
12	export function extractTopicText(
13	  subject: unknown,
14	  bookId: string,
15	  chapterId: string,
16	  topicId: string
17	): string {
18	  const s = subject as {
19	    books?: Array<{
20	      _id?: mongoose.Types.ObjectId;
21	      chapters?: Array<{
22	        _id?: mongoose.Types.ObjectId;
23	        topics?: Array<{
24	          _id?: mongoose.Types.ObjectId;
25	          paragraphs?: Array<{ order?: number; content?: { text?: string } }>;
26	        }>;
27	      }>;
28	    }>;
29	  };
30	  const book = s.books?.find((b) => b._id?.toString() === bookId);
31	  if (!book) return '';
32	  const chapter = book.chapters?.find((c) => c._id?.toString() === chapterId);
33	  if (!chapter) return '';
34	  const topic = chapter.topics?.find((t) => t._id?.toString() === topicId);
35	  if (!topic) return '';
36	  return (topic.paragraphs || [])
37	    .sort((a, b) => (a.order ?? 0) - (b.order ?? 0))
38	    .map((p) => (p.content?.text || '').trim())
39	    .filter(Boolean)
40	    .join('\n\n');
41	}
