366	  /**
367	   * Консолидация урока узла КТП: из фрагментов учебников разных классов по ОДНОЙ теме
368	   * собирает один связный дедуплицированный урок (или 2–4, если материала много).
369	   */
370	  async consolidateLessonContent(input: {
371	    subjectTitle: string;
372	    nodeTitle: string;
373	    sources: Array<{ label: string; text: string }>;
374	  }): Promise<Array<{ title: string; summary?: string; content: string }>> {
375	    const apiKey = process.env.OPENAI_API_KEY;
376	    if (!apiKey) throw AppError.badRequest('OPENAI_API_KEY is not set');
377	
378	    const MAX_TOTAL = 24000;
379	    let used = 0;
380	    const blocks: string[] = [];
381	    for (const s of input.sources) {
382	      if (used >= MAX_TOTAL) break;
383	      const remaining = MAX_TOTAL - used;
384	      const t = s.text.length > remaining ? `${s.text.slice(0, remaining)}\n[обрезано]` : s.text;
385	      used += t.length;
386	      blocks.push(`### Источник: ${s.label}\n${t}`);
387	    }
388	    const sourcesBlock = blocks.join('\n\n');
389	
390	    const prompt = [
391	      'Ниже — фрагменты учебников разных классов по ОДНОЙ теме. Собери из них единый урок для ученика.',
392	      'Требования:',
393	      '- Объедини материал, убери дословные повторы между источниками; сохрани ВСЕ различные факты (ничего важного не теряй).',
394	      '- Упорядочи изложение от базового к продвинутому.',
395	      '- Пиши на языке источников. НЕ добавляй фактов, которых нет в источниках. Не упоминай «класс/учебник/источник» в тексте.',
396	      '- По умолчанию ОДИН урок. Если материала очень много — раздели на 2–4 последовательных урока по подтемам.',
397	      'Верни ТОЛЬКО строгий JSON без Markdown-обёртки:',
398	      '{ "lessons": [ { "title": "название урока", "summary": "1-2 предложения", "content": "тело урока в Markdown" } ] }',
399	      '',
400	      `Предмет: ${input.subjectTitle}. Тема: ${input.nodeTitle}.`,
401	      '',
402	      'Источники:',
403	      sourcesBlock
404	    ].join('\n');
405	
406	    const response = await fetch('https://api.openai.com/v1/chat/completions', {
407	      method: 'POST',
408	      headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${apiKey}` },
409	      body: JSON.stringify({
410	        model: MODEL,
411	        temperature: 0.3,
412	        max_tokens: 3000,
413	        messages: [
414	          {
415	            role: 'system',
416	            content: 'Ты методист; собираешь единый дедуплицированный урок строго из переданных фрагментов учебников. Ответ — строгий JSON.'
417	          },
418	          { role: 'user', content: prompt }
419	        ]
420	      })
421	    });
422	
423	    if (!response.ok) {
424	      const errText = await response.text();
425	      console.error('[roadmap AI] lesson consolidation failed', response.status, errText);
426	      throw new Error(`OpenAI: ${response.status}`);
427	    }
428	
429	    const data = (await response.json()) as { choices?: Array<{ message?: { content?: string } }> };
430	    const raw = data.choices?.[0]?.message?.content ?? '';
431	    const parsed = parseJsonObject(raw);
432	    const lessonsRaw = parsed.lessons;
433	    if (!Array.isArray(lessonsRaw) || lessonsRaw.length === 0) {
434	      throw AppError.badRequest('AI returned no lessons');
435	    }
436	    return lessonsRaw
437	      .map((l: any) => ({
438	        title: String(l?.title ?? '').trim() || input.nodeTitle,
439	        ...(typeof l?.summary === 'string' && l.summary.trim() ? { summary: l.summary.trim() } : {}),
440	        content: String(l?.content ?? '').trim()
441	      }))
442	      .filter((l) => l.content);
443	  }
444	}
